/**
 * Secret Validation Service
 * Validates all required secrets at startup
 */

export interface SecretValidationResult {
  valid: boolean;
  errors: string[];
}

export function validateRequiredSecrets(): SecretValidationResult {
  const errors: string[] = [];

  const requiredSecrets = [
    { name: 'JWT_SECRET', minLength: 32 },
    { name: 'DATABASE_URL', minLength: 10 },
  ];

  const sensitiveSecrets = [
    'OPENAI_API_KEY',
    'SENDGRID_API_KEY',
    'AWS_SECRET_ACCESS_KEY',
    'BACKUP_ENCRYPTION_KEY',
  ];

  for (const secret of requiredSecrets) {
    const value = process.env[secret.name];
    if (!value) {
      errors.push(`Missing required secret: ${secret.name}`);
    } else if (value.length < secret.minLength) {
      errors.push(`${secret.name} must be at least ${secret.minLength} characters`);
    }
  }

  for (const name of sensitiveSecrets) {
    if (process.env[name] && process.env.NODE_ENV === 'production') {
      // Validate format patterns
      if (name === 'OPENAI_API_KEY' && !process.env[name]?.startsWith('sk-')) {
        errors.push(`Invalid ${name} format`);
      }
    }
  }

  return { valid: errors.length === 0, errors };
}

export function assertSecretsValid(): void {
  const result = validateRequiredSecrets();
  if (!result.valid) {
    console.error('SECRET VALIDATION FAILED:');
    result.errors.forEach(err => console.error(`  - ${err}`));
    process.exit(1);
  }
}

