/**
 * Security Headers Middleware
 * Implements OWASP recommended security headers
 */

import { FastifyRequest, FastifyReply, HookHandlerDoneFunction } from 'fastify';

export interface SecurityHeadersConfig {
  enableHSTS: boolean;
  hstsMaxAge: number;
  enableCSP: boolean;
  cspDirectives: Record<string, string[]>;
  enableFrameOptions: boolean;
  enableXSSFilter: boolean;
  enableNoSniff: boolean;
  enableReferrerPolicy: boolean;
}

const defaultConfig: SecurityHeadersConfig = {
  enableHSTS: true,
  hstsMaxAge: 31536000, // 1 year
  enableCSP: true,
  cspDirectives: {
    'default-src': ["'self'"],
    'script-src': ["'self'"],
    'style-src': ["'self'", "'unsafe-inline'"],
    'img-src': ["'self'", 'data:', 'https:'],
    'font-src': ["'self'"],
    'connect-src': ["'self'"],
    'frame-ancestors': ["'none'"],
    'base-uri': ["'self'"],
    'form-action': ["'self'"],
  },
  enableFrameOptions: true,
  enableXSSFilter: true,
  enableNoSniff: true,
  enableReferrerPolicy: true,
};

export function createSecurityHeadersMiddleware(config: Partial<SecurityHeadersConfig> = {}) {
  const finalConfig = { ...defaultConfig, ...config };

  return async function securityHeadersMiddleware(
    request: FastifyRequest,
    reply: FastifyReply,
    done: HookHandlerDoneFunction
  ): Promise<void> {
    // HSTS - HTTP Strict Transport Security
    if (finalConfig.enableHSTS && process.env.NODE_ENV === 'production') {
      reply.header(
        'Strict-Transport-Security',
        `max-age=${finalConfig.hstsMaxAge}; includeSubDomains; preload`
      );
    }

    // Content Security Policy
    if (finalConfig.enableCSP) {
      const cspValue = Object.entries(finalConfig.cspDirectives)
        .map(([directive, values]) => `${directive} ${values.join(' ')}`)
        .join('; ');
      reply.header('Content-Security-Policy', cspValue);
    }

    // X-Frame-Options (clickjacking protection)
    if (finalConfig.enableFrameOptions) {
      reply.header('X-Frame-Options', 'DENY');
    }

    // X-XSS-Protection
    if (finalConfig.enableXSSFilter) {
      reply.header('X-XSS-Protection', '1; mode=block');
    }

    // X-Content-Type-Options
    if (finalConfig.enableNoSniff) {
      reply.header('X-Content-Type-Options', 'nosniff');
    }

    // Referrer-Policy
    if (finalConfig.enableReferrerPolicy) {
      reply.header('Referrer-Policy', 'strict-origin-when-cross-origin');
    }

    // Additional security headers
    reply.header('X-DNS-Prefetch-Control', 'off');
    reply.header('X-Download-Options', 'noopen');
    reply.header('X-Permitted-Cross-Domain-Policies', 'none');
    reply.header('Permissions-Policy', 'camera=(), microphone=(), geolocation=()');

    // Remove server identification headers
    reply.removeHeader('X-Powered-By');

    done();
  };
}

export const securityHeadersMiddleware = createSecurityHeadersMiddleware();

