/**
 * HTTPS Redirect Middleware
 * Forces HTTPS in production environments
 */

import { FastifyRequest, FastifyReply, HookHandlerDoneFunction } from 'fastify';

export async function httpsRedirectMiddleware(
  request: FastifyRequest,
  reply: FastifyReply,
  done: HookHandlerDoneFunction
): Promise<void> {
  if (process.env.NODE_ENV !== 'production') {
    done();
    return;
  }

  // Check for X-Forwarded-Proto header (common in reverse proxy setups)
  const protocol = request.headers['x-forwarded-proto'];
  const host = request.headers.host;

  if (protocol === 'http' && host) {
    const httpsUrl = `https://${host}${request.url}`;
    reply.code(301).redirect(httpsUrl);
    return;
  }

  done();
}

