/**
 * Global Error Handler Middleware
 * Sanitizes error responses to prevent information disclosure
 */

import { FastifyError, FastifyRequest, FastifyReply } from 'fastify';
import { randomUUID } from 'crypto';
import { logger } from '../utils/logger.js';

export interface SanitizedError {
  error: string;
  message: string;
  errorId: string;
  statusCode: number;
}

const GENERIC_MESSAGES: Record<number, string> = {
  400: 'Invalid request',
  401: 'Authentication required',
  403: 'Access denied',
  404: 'Resource not found',
  409: 'Conflict with current state',
  422: 'Validation failed',
  429: 'Too many requests',
  500: 'Internal server error',
  502: 'Service unavailable',
  503: 'Service temporarily unavailable',
};

// Error types that are safe to expose details for
const SAFE_ERROR_TYPES = [
  'ValidationError',
  'ZodError',
  'NotFoundError',
  'ConflictError',
];

export function globalErrorHandler(
  error: FastifyError,
  request: FastifyRequest,
  reply: FastifyReply
): void {
  const errorId = randomUUID();
  const statusCode = error.statusCode || 500;
  const isProduction = process.env.NODE_ENV === 'production';

  // Log full error details internally
  logger.error('Request error', {
    errorId,
    statusCode,
    method: request.method,
    url: request.url,
    userId: (request as any).user?.id,
    error: {
      name: error.name,
      message: error.message,
      stack: error.stack,
      code: error.code,
    },
  });

  // Determine safe message for response
  let userMessage: string;

  if (!isProduction) {
    // In development, show more details
    userMessage = error.message;
  } else if (SAFE_ERROR_TYPES.includes(error.name)) {
    // Safe errors can show their message
    userMessage = error.message;
  } else if (statusCode < 500) {
    // Client errors can use error message
    userMessage = error.message || GENERIC_MESSAGES[statusCode] || 'Request failed';
  } else {
    // Server errors get generic message
    userMessage = GENERIC_MESSAGES[statusCode] || 'An unexpected error occurred';
  }

  const response: SanitizedError = {
    error: error.name || 'Error',
    message: userMessage,
    errorId,
    statusCode,
  };

  reply.code(statusCode).send(response);
}

// Custom error classes for safe exposure
export class ValidationError extends Error {
  statusCode = 400;
  constructor(message: string) {
    super(message);
    this.name = 'ValidationError';
  }
}

export class NotFoundError extends Error {
  statusCode = 404;
  constructor(message: string) {
    super(message);
    this.name = 'NotFoundError';
  }
}

export class ConflictError extends Error {
  statusCode = 409;
  constructor(message: string) {
    super(message);
    this.name = 'ConflictError';
  }
}

