/**
 * Field Encryption Service
 * Provides application-level encryption for PII fields
 * Uses AES-256-GCM with envelope encryption
 */

import { createCipheriv, createDecipheriv, randomBytes, createHash, scryptSync } from 'crypto';

const ALGORITHM = 'aes-256-gcm';
const IV_LENGTH = 16;
const AUTH_TAG_LENGTH = 16;
const ENCRYPTED_PREFIX = 'enc:';

export class FieldEncryptionService {
  private readonly masterKey: Buffer;

  constructor() {
    const encryptionKey = process.env.PII_ENCRYPTION_KEY;
    if (!encryptionKey) {
      throw new Error('PII_ENCRYPTION_KEY environment variable is required');
    }

    // Derive a 32-byte key using scrypt
    this.masterKey = scryptSync(encryptionKey, 'legal-rag-salt', 32);
  }

  /**
   * Encrypt a field value
   */
  encrypt(plaintext: string): string {
    if (!plaintext) return plaintext;

    const iv = randomBytes(IV_LENGTH);
    const cipher = createCipheriv(ALGORITHM, this.masterKey, iv);

    let encrypted = cipher.update(plaintext, 'utf8', 'hex');
    encrypted += cipher.final('hex');

    const authTag = cipher.getAuthTag();

    // Format: enc:iv:authTag:ciphertext
    return `${ENCRYPTED_PREFIX}${iv.toString('hex')}:${authTag.toString('hex')}:${encrypted}`;
  }

  /**
   * Decrypt a field value
   */
  decrypt(encrypted: string): string {
    if (!encrypted || !encrypted.startsWith(ENCRYPTED_PREFIX)) {
      return encrypted;
    }

    const parts = encrypted.slice(ENCRYPTED_PREFIX.length).split(':');
    if (parts.length !== 3) {
      throw new Error('Invalid encrypted format');
    }

    const [ivHex, authTagHex, ciphertext] = parts;
    const iv = Buffer.from(ivHex, 'hex');
    const authTag = Buffer.from(authTagHex, 'hex');

    const decipher = createDecipheriv(ALGORITHM, this.masterKey, iv);
    decipher.setAuthTag(authTag);

    let decrypted = decipher.update(ciphertext, 'hex', 'utf8');
    decrypted += decipher.final('utf8');

    return decrypted;
  }

  /**
   * Check if a value is encrypted
   */
  isEncrypted(value: string): boolean {
    return value?.startsWith(ENCRYPTED_PREFIX) ?? false;
  }

  /**
   * Create a deterministic hash for searchable encrypted fields
   * WARNING: This reduces security but enables searching
   */
  createSearchHash(plaintext: string): string {
    if (!plaintext) return '';
    const hash = createHash('sha256');
    hash.update(this.masterKey);
    hash.update(plaintext.toLowerCase().trim());
    return hash.digest('hex');
  }
}

// Singleton instance
let instance: FieldEncryptionService | null = null;

export function getFieldEncryptionService(): FieldEncryptionService {
  if (!instance) {
    instance = new FieldEncryptionService();
  }
  return instance;
}

// Prisma middleware for automatic encryption/decryption
export function createPrismaEncryptionMiddleware() {
  const encryptedFields: Record<string, string[]> = {
    User: ['phoneNumber', 'address', 'barNumber', 'lawFirm', 'bio', 'twoFactorSecret'],
    Case: ['clientName'],
    PaymentMethod: ['cardLast4'],
    PaymentProof: ['accountNumber'],
  };

  const service = getFieldEncryptionService();

  return async (params: any, next: any) => {
    const { model, action, args } = params;
    const fieldsToEncrypt = encryptedFields[model];

    if (!fieldsToEncrypt) {
      return next(params);
    }

    // Encrypt on create/update
    if (['create', 'update', 'upsert'].includes(action) && args.data) {
      for (const field of fieldsToEncrypt) {
        if (args.data[field] && !service.isEncrypted(args.data[field])) {
          args.data[field] = service.encrypt(args.data[field]);
        }
      }
    }

    const result = await next(params);

    // Decrypt on read
    if (result && ['findUnique', 'findFirst', 'findMany'].includes(action)) {
      const decryptRecord = (record: any) => {
        if (!record) return record;
        for (const field of fieldsToEncrypt) {
          if (record[field]) {
            record[field] = service.decrypt(record[field]);
          }
        }
        return record;
      };

      if (Array.isArray(result)) {
        return result.map(decryptRecord);
      }
      return decryptRecord(result);
    }

    return result;
  };
}

/**
 * GDPR Data Deletion Service
 * Implements Article 17 - Right to Erasure
 */

import { PrismaClient } from '@prisma/client';
import { logger } from '../../utils/logger.js';

export interface DeletionResult {
  success: boolean;
  deletedEntities: Record<string, number>;
  errors: string[];
  timestamp: Date;
  requestId: string;
}

export class DataDeletionService {
  private prisma: PrismaClient;

  constructor(prisma: PrismaClient) {
    this.prisma = prisma;
  }

  /**
   * Permanently delete all user data (hard delete)
   */
  async deleteAllUserData(userId: string, requestId: string): Promise<DeletionResult> {
    const deletedEntities: Record<string, number> = {};
    const errors: string[] = [];

    logger.info('Starting GDPR data deletion', { userId, requestId });

    try {
      await this.prisma.$transaction(async (tx) => {
        // Delete in order of dependencies (children first)

        // 1. Delete document chunks
        const docChunks = await tx.documentChunk.deleteMany({
          where: { document: { userId } }
        });
        deletedEntities['documentChunks'] = docChunks.count;

        // 2. Delete documents
        const docs = await tx.document.deleteMany({ where: { userId } });
        deletedEntities['documents'] = docs.count;

        // 3. Delete legal document chunks and legal documents
        const legalDocChunks = await tx.legalDocumentChunk.deleteMany({
          where: { legalDocument: { uploadedBy: userId } }
        });
        deletedEntities['legalDocumentChunks'] = legalDocChunks.count;

        const legalDocs = await tx.legalDocument.deleteMany({ where: { uploadedBy: userId } });
        deletedEntities['legalDocuments'] = legalDocs.count;

        // 4. Delete cases and related data
        const cases = await tx.case.deleteMany({ where: { userId } });
        deletedEntities['cases'] = cases.count;

        // 5. Delete query logs (anonymize instead of delete for analytics)
        const queryLogs = await tx.queryLog.updateMany({
          where: { userId },
          data: { userId: null, ipAddress: null, query: '[DELETED]' }
        });
        deletedEntities['queryLogs'] = queryLogs.count;

        // 6. Delete audit logs user reference (keep for compliance)
        const auditLogs = await tx.auditLog.updateMany({
          where: { userId },
          data: { userId: null, ipAddress: null }
        });
        deletedEntities['auditLogs'] = auditLogs.count;

        // 7. Delete notifications
        const notifications = await tx.notification.deleteMany({ where: { userId } });
        deletedEntities['notifications'] = notifications.count;

        // 8. Delete subscriptions and payments
        const payments = await tx.payment.deleteMany({ where: { userId } });
        deletedEntities['payments'] = payments.count;

        const subscriptions = await tx.subscription.deleteMany({ where: { userId } });
        deletedEntities['subscriptions'] = subscriptions.count;

        // 9. Delete API keys
        const apiKeys = await tx.apiKey.deleteMany({ where: { userId } });
        deletedEntities['apiKeys'] = apiKeys.count;

        // 10. Delete user quotas and settings
        const quotas = await tx.userQuota.deleteMany({ where: { userId } });
        deletedEntities['userQuotas'] = quotas.count;

        const settings = await tx.userSettings.deleteMany({ where: { userId } });
        deletedEntities['userSettings'] = settings.count;

        // 11. Finally delete the user
        await tx.user.delete({ where: { id: userId } });
        deletedEntities['users'] = 1;

        // 12. Create deletion record for audit
        await tx.auditLog.create({
          data: {
            action: 'GDPR_DATA_DELETION',
            entity: 'User',
            entityId: requestId,
            changes: {
              deletedEntities,
              originalUserId: '[REDACTED]',
              requestType: 'right_to_erasure'
            },
            success: true
          }
        });
      });

      logger.info('GDPR data deletion completed', { requestId, deletedEntities });

      return {
        success: true,
        deletedEntities,
        errors,
        timestamp: new Date(),
        requestId
      };
    } catch (error) {
      logger.error('GDPR data deletion failed', { requestId, error });
      errors.push((error as Error).message);

      return {
        success: false,
        deletedEntities,
        errors,
        timestamp: new Date(),
        requestId
      };
    }
  }

  /**
   * Anonymize user data (soft delete alternative)
   */
  async anonymizeUserData(userId: string): Promise<DeletionResult> {
    const requestId = `anon-${Date.now()}`;
    const deletedEntities: Record<string, number> = {};

    try {
      await this.prisma.$transaction(async (tx) => {
        // Anonymize user record
        await tx.user.update({
          where: { id: userId },
          data: {
            email: `deleted-${userId}@anonymized.local`,
            name: '[DELETED]',
            passwordHash: null,
            phoneNumber: null,
            address: null,
            city: null,
            country: null,
            barNumber: null,
            lawFirm: null,
            bio: null,
            avatarUrl: null,
            isActive: false,
            twoFactorSecret: null,
            twoFactorBackupCodes: [],
          }
        });
        deletedEntities['users'] = 1;
      });

      return {
        success: true,
        deletedEntities,
        errors: [],
        timestamp: new Date(),
        requestId
      };
    } catch (error) {
      return {
        success: false,
        deletedEntities,
        errors: [(error as Error).message],
        timestamp: new Date(),
        requestId
      };
    }
  }
}

/**
 * GDPR Data Export Service
 * Implements Article 20 - Right to Data Portability
 */

import { PrismaClient } from '@prisma/client';
import { createGzip } from 'zlib';
import { pipeline } from 'stream/promises';
import { createWriteStream } from 'fs';
import { mkdir, unlink } from 'fs/promises';
import { join } from 'path';
import { logger } from '../../utils/logger.js';

export interface ExportResult {
  success: boolean;
  filePath?: string;
  fileSize?: number;
  format: string;
  timestamp: Date;
  expiresAt: Date;
}

export class DataExportService {
  private prisma: PrismaClient;
  private exportDir: string;

  constructor(prisma: PrismaClient) {
    this.prisma = prisma;
    this.exportDir = process.env.DATA_EXPORT_DIR || './exports';
  }

  /**
   * Export all user data in JSON format
   */
  async exportUserData(userId: string): Promise<ExportResult> {
    const timestamp = new Date();

    try {
      // Gather all user data
      const userData = await this.gatherUserData(userId);

      // Create export file
      const exportId = `export-${userId}-${timestamp.getTime()}`;
      await mkdir(this.exportDir, { recursive: true });
      const filePath = join(this.exportDir, `${exportId}.json.gz`);

      // Write compressed JSON
      const jsonData = JSON.stringify(userData, null, 2);
      const gzip = createGzip();
      const destination = createWriteStream(filePath);

      await new Promise<void>((resolve, reject) => {
        gzip.on('error', reject);
        destination.on('error', reject);
        destination.on('finish', resolve);

        gzip.write(jsonData);
        gzip.pipe(destination);
        gzip.end();
      });

      // Log export request
      await this.prisma.auditLog.create({
        data: {
          userId,
          action: 'GDPR_DATA_EXPORT',
          entity: 'User',
          entityId: userId,
          changes: { exportId, format: 'json.gz' },
          success: true
        }
      });

      logger.info('Data export completed', { userId, exportId });

      return {
        success: true,
        filePath,
        format: 'application/gzip',
        timestamp,
        expiresAt: new Date(timestamp.getTime() + 7 * 24 * 60 * 60 * 1000) // 7 days
      };
    } catch (error) {
      logger.error('Data export failed', { userId, error });
      throw error;
    }
  }

  private async gatherUserData(userId: string): Promise<Record<string, any>> {
    const user = await this.prisma.user.findUnique({
      where: { id: userId },
      include: {
        cases: { include: { documents: true } },
        legalDocuments: true,
        quota: true,
        notifications: true,
        queryLogs: true,
        subscriptions: true,
        payments: true,
        settings: true,
        usageHistory: true,
        apiKeys: { select: { name: true, lastUsed: true, createdAt: true } },
      }
    });

    if (!user) {
      throw new Error('User not found');
    }

    // Remove sensitive fields
    const { passwordHash, twoFactorSecret, twoFactorBackupCodes, ...safeUser } = user;

    return {
      exportMetadata: {
        exportDate: new Date().toISOString(),
        format: 'JSON',
        version: '1.0',
        dataController: 'Poweria Legal',
        dataSubject: user.email,
      },
      personalData: safeUser,
    };
  }
}
